echo "<br><br>";
function generateUniqueData($numRows, $numRangeStart, $numRangeEnd) {
    $uniqueData = []; // Array to store unique rows

    while (count($uniqueData) < $numRows) {
        // Generate a row with unique numbers
        $row = range($numRangeStart, $numRangeEnd);
        shuffle($row); // Shuffle the array to get random order
        $row = array_slice($row, 0, 5); // Take the first 5 numbers

        // Sort the row for consistent output (optional)
        sort($row);
        
        // Store the row as a string to check for uniqueness
        $rowString = implode(',', $row);
        if (!in_array($rowString, $uniqueData)) {
            $uniqueData[] = $rowString; // Add to the unique data if not present
        }
    }

    return $uniqueData;
}
